-- hanmam tbl_user → AMB (amb_users + amb_hr_employees + amb_hr_employees_kr) 마이그레이션
-- 실행: cat scripts/migration/hanmam/002-migrate-user.sql | docker exec -i amb-postgres psql -U amb_user -d db_amb_hanmam
