BEGIN;

-- ═══════════════════════════════════════════════════════════
-- 1) 임시 테이블 생성
-- ═══════════════════════════════════════════════════════════
CREATE TEMP TABLE tmp_user (
  user_no         INT PRIMARY KEY,
  org_no          INT,
  comp_no         INT,
  exp_comp_no     INT,
  user_id         VARCHAR(100),
  user_name       VARCHAR(100),
  password        VARCHAR(200),
  work_status     CHAR(1),        -- W=재직, R=퇴사, L=휴직
  work_type       INT,
  user_auth       INT,
  admin_auth_det  INT,
  user_rank       VARCHAR(50),
  initial         VARCHAR(20),
  reg_datetime    TIMESTAMP,
  birth_date      DATE,
  join_date       DATE,
  retire_date     DATE,
  bank_name       VARCHAR(50),
  bank_account    VARCHAR(50),
  phone_no        VARCHAR(30),
  office_phone_no VARCHAR(30),
  email           VARCHAR(200),
  total_cost      INT,
  del_yn          CHAR(1),
  id_no           VARCHAR(50),
  home_address    TEXT,
  note            TEXT,
  attach_file_id  VARCHAR(200),
  -- 생성 UUID
  new_usr_id      UUID DEFAULT gen_random_uuid(),
  new_emp_id      UUID DEFAULT gen_random_uuid(),
  new_ekr_id      UUID DEFAULT gen_random_uuid(),
  ent_id          UUID
);

