-- ═══════════════════════════════════════════════════════════
-- 3) ID_NO 탭 문자 정리
-- ═══════════════════════════════════════════════════════════
UPDATE tmp_user SET id_no = TRIM(BOTH E'\t' FROM id_no) WHERE id_no LIKE E'%\t%';

-- 3-b) 중복 이메일 처리: 같은 comp_no 내 동일 EMAIL → 후순위 사용자에게 USER_ID 기반 이메일
UPDATE tmp_user t1
SET email = ''
WHERE EXISTS (
  SELECT 1 FROM tmp_user t2
  WHERE LOWER(TRIM(t2.email)) = LOWER(TRIM(t1.email))
    AND t2.comp_no = t1.comp_no
    AND t2.user_no < t1.user_no
    AND NULLIF(TRIM(t2.email), '') IS NOT NULL
)
AND NULLIF(TRIM(t1.email), '') IS NOT NULL;

-- ═══════════════════════════════════════════════════════════
-- 4) COMP_NO → ent_id 매핑
-- ═══════════════════════════════════════════════════════════
UPDATE tmp_user SET ent_id = (SELECT ent_id FROM amb_hr_entities WHERE ent_code = 'KR01') WHERE comp_no = 1;
UPDATE tmp_user SET ent_id = (SELECT ent_id FROM amb_hr_entities WHERE ent_code = 'GL01') WHERE comp_no = 3;
UPDATE tmp_user SET ent_id = (SELECT ent_id FROM amb_hr_entities WHERE ent_code = 'KR01') WHERE comp_no = 9;
-- COMP_NO=0 (admin 계정) → KR01로 배정
UPDATE tmp_user SET ent_id = (SELECT ent_id FROM amb_hr_entities WHERE ent_code = 'KR01') WHERE comp_no = 0;

-- ═══════════════════════════════════════════════════════════
-- 5) amb_users INSERT (202건)
-- ═══════════════════════════════════════════════════════════
INSERT INTO amb_users (
  usr_id, usr_email, usr_password, usr_name, usr_unit,
  usr_role, usr_level_code, usr_status, usr_must_change_pw,
  usr_join_method, usr_company_id, usr_job_title, usr_phone,
  usr_company_email, usr_timezone, usr_locale, usr_deleted_at
)
SELECT
  t.new_usr_id,
  -- EMAIL에 @가 있으면 EMAIL 사용, 없으면 USER_ID 기반 생성
  CASE
    WHEN NULLIF(TRIM(t.email), '') IS NOT NULL AND t.email LIKE '%@%' THEN LOWER(TRIM(t.email))
    ELSE LOWER(t.user_id) || '@hanmam.local'
  END,
  -- bcrypt 해시 기본 비밀번호 (ChangeMe1!)
  crypt('ChangeMe1!', gen_salt('bf', 10)),
  t.user_name,
  -- usr_unit: 부서명 (varchar(30))
  LEFT(COALESCE(
    (SELECT u.unt_name FROM amb_units u
     JOIN amb_migration_pk_map m ON m.map_target_pk = u.unt_id
     WHERE m.map_source_table = 'tbl_org' AND m.map_source_pk = t.org_no LIMIT 1),
    ''
  ), 30),
  -- usr_role
  CASE
    WHEN t.user_auth & 1 = 1 THEN 'MASTER'
    WHEN t.user_rank IN ('사장','대표','전무','상무','이사') THEN 'MASTER'
    ELSE 'MEMBER'
  END,
  -- usr_level_code
  CASE
    WHEN t.user_auth & 1 = 1 THEN 'ADMIN_LEVEL'
    ELSE 'USER_LEVEL'
  END,
  -- usr_status
  CASE t.work_status
    WHEN 'W' THEN 'ACTIVE'
    WHEN 'R' THEN 'INACTIVE'
    WHEN 'L' THEN 'SUSPENDED'
    ELSE 'INACTIVE'
  END,
  TRUE,
  'MIGRATE',
  t.ent_id,
  NULLIF(TRIM(t.user_rank), ''),
  NULLIF(TRIM(t.phone_no), ''),
  -- usr_company_email: EMAIL과 usr_email이 다를 때만
  CASE
    WHEN NULLIF(TRIM(t.email), '') IS NOT NULL AND t.email LIKE '%@%' THEN NULL
    ELSE NULLIF(TRIM(t.email), '')
  END,
  'Asia/Seoul',
  'ko',
  CASE WHEN t.del_yn = 'Y' THEN NOW() ELSE NULL END
FROM tmp_user t;

-- ═══════════════════════════════════════════════════════════
-- 6) amb_hr_employees INSERT (202건)
-- ═══════════════════════════════════════════════════════════
INSERT INTO amb_hr_employees (
  emp_id, ent_id, usr_id, emp_code, emp_full_name,
  emp_nationality, emp_cccd_number, emp_start_date, emp_end_date,
  emp_status, emp_contract_type, emp_department, emp_position,
  emp_memo
)
SELECT
  t.new_emp_id,
  t.ent_id,
  t.new_usr_id,
  'HM-' || LPAD(t.user_no::text, 4, '0'),
  t.user_name,
  'KOREAN',
  'HM-TEMP-' || t.user_no::text,
  COALESCE(t.join_date, t.reg_datetime::date),
  t.retire_date,
  CASE t.work_status
    WHEN 'W' THEN 'ACTIVE'
    WHEN 'R' THEN 'RESIGNED'
    WHEN 'L' THEN 'ON_LEAVE'
    ELSE 'RESIGNED'
  END,
  'EMPLOYEE',
  COALESCE(
    (SELECT u.unt_name FROM amb_units u
     JOIN amb_migration_pk_map m ON m.map_target_pk = u.unt_id
     WHERE m.map_source_table = 'tbl_org' AND m.map_source_pk = t.org_no LIMIT 1),
    '미배정'
  ),
  COALESCE(NULLIF(TRIM(t.user_rank), ''), '사원'),
  NULLIF(TRIM(
    COALESCE('생년월일: ' || t.birth_date::text || E'\n', '') ||
    COALESCE('자택주소: ' || NULLIF(TRIM(t.home_address), '') || E'\n', '') ||
    COALESCE('비고: ' || NULLIF(TRIM(t.note), ''), '')
  ), '')
FROM tmp_user t;

-- ═══════════════════════════════════════════════════════════
-- 7) amb_hr_employees_kr INSERT (한국 고유 데이터)
-- ═══════════════════════════════════════════════════════════
INSERT INTO amb_hr_employees_kr (
  ekr_id, emp_id, ekr_resident_no, ekr_employee_type, ekr_bank_account
)
SELECT
  t.new_ekr_id,
  t.new_emp_id,
  NULLIF(TRIM(t.id_no), ''),
  'REGULAR',
  CASE
    WHEN NULLIF(TRIM(t.bank_name), '') IS NOT NULL OR NULLIF(TRIM(t.bank_account), '') IS NOT NULL
    THEN TRIM(COALESCE(NULLIF(TRIM(t.bank_name), ''), '') || ' ' || COALESCE(NULLIF(TRIM(t.bank_account), ''), ''))
    ELSE NULL
  END
FROM tmp_user t;

-- ═══════════════════════════════════════════════════════════
-- 8) amb_user_unit_roles INSERT (부서 배정)
-- ═══════════════════════════════════════════════════════════
INSERT INTO amb_user_unit_roles (
  usr_id, unt_id, uur_role, uur_is_primary, uur_started_at, uur_ended_at
)
SELECT
  t.new_usr_id,
  m.map_target_pk,
  'MEMBER',
  TRUE,
  COALESCE(t.join_date, t.reg_datetime::date),
  t.retire_date
FROM tmp_user t
JOIN amb_migration_pk_map m ON m.map_source_table = 'tbl_org' AND m.map_source_pk = t.org_no;

-- ═══════════════════════════════════════════════════════════
-- 9) PK 매핑 기록
-- ═══════════════════════════════════════════════════════════
INSERT INTO amb_migration_pk_map (map_source_table, map_source_pk, map_target_table, map_target_pk)
SELECT 'tbl_user', user_no, 'amb_users', new_usr_id FROM tmp_user;

INSERT INTO amb_migration_pk_map (map_source_table, map_source_pk, map_target_table, map_target_pk)
SELECT 'tbl_user', user_no, 'amb_hr_employees', new_emp_id FROM tmp_user;

-- ═══════════════════════════════════════════════════════════
-- 10) amb_units.unt_leader_id 업데이트
-- ═══════════════════════════════════════════════════════════
CREATE TEMP TABLE tmp_org_leader (
  org_no    INT PRIMARY KEY,
  leader_no INT
);

INSERT INTO tmp_org_leader (org_no, leader_no) VALUES
  (104, 13), (122, 7), (211, 44), (311, 635), (471, 7), (487, 634),
  (33, 335), (411, 44), (461, 447), (462, 447), (472, 16), (473, 571),
  (475, 25), (476, 556), (477, 433), (478, 0), (479, 68), (480, 7),
  (482, 573), (483, 566), (484, 68), (485, 616), (486, 433), (488, 0),
  (489, 422), (490, 654), (492, 479),
  (391, 120), (392, 3), (404, 186), (491, 651),
  (401, 9), (402, 549), (403, 453), (421, 27), (481, 28);

UPDATE amb_units u
SET unt_leader_id = tu.new_usr_id
FROM tmp_org_leader ol
JOIN amb_migration_pk_map om ON om.map_source_table = 'tbl_org' AND om.map_source_pk = ol.org_no
JOIN tmp_user tu ON tu.user_no = ol.leader_no
WHERE u.unt_id = om.map_target_pk
  AND ol.leader_no > 0;

-- ═══════════════════════════════════════════════════════════
-- 11) amb_hr_entities.ent_ceo_user_id 업데이트
-- ═══════════════════════════════════════════════════════════
UPDATE amb_hr_entities
SET ent_ceo_user_id = (SELECT new_usr_id FROM tmp_user WHERE user_no = 2)
WHERE ent_code = 'KR01';

UPDATE amb_hr_entities
SET ent_ceo_user_id = (SELECT new_usr_id FROM tmp_user WHERE user_no = 3)
WHERE ent_code = 'GL01';

-- ═══════════════════════════════════════════════════════════
-- 12) amb_user_unit_roles 리더 역할 업데이트
-- ═══════════════════════════════════════════════════════════
UPDATE amb_user_unit_roles uur
SET uur_role = 'UNIT_HEAD'
FROM amb_units u
WHERE uur.unt_id = u.unt_id
  AND u.unt_leader_id = uur.usr_id
  AND u.unt_level = 1;

UPDATE amb_user_unit_roles uur
SET uur_role = 'TEAM_LEAD'
FROM amb_units u
WHERE uur.unt_id = u.unt_id
  AND u.unt_leader_id = uur.usr_id
  AND u.unt_level = 2;

-- ═══════════════════════════════════════════════════════════
-- 13) 정리
-- ═══════════════════════════════════════════════════════════
DROP TABLE tmp_org_leader;
DROP TABLE tmp_user;

COMMIT;
